function Navbar() {
  return (
    <nav>
      <ul>
        <li>
          <Link to="/">Personas Registradas</Link>
        </li>
        <li>
          <Link to="/horario">Horario</Link>
        </li>
        <li>
          <Link to="/materias">Materias Matriculadas</Link>
        </li>
      </ul>
    </nav>
  );
}

export default Navbar;
